"use client";
import { useState } from "react";
import { AnimatePresence, motion, useReducedMotion } from "framer-motion";
export default function EdgeNoteTransition(){const [reviewed,setReviewed]=useState(false);const reduced=useReducedMotion();const label=reviewed?'Reviewed':'Draft';return <section className="w-full max-w-sm rounded-[22px] border border-[#ececee] bg-[#f4f5f6] p-5 shadow-[0_10px_28px_rgba(17,17,17,.06)]"><div className="relative overflow-hidden rounded-2xl border border-[#ececee] bg-white p-5"><motion.i aria-hidden animate={{x:reviewed?0:-28}} transition={reduced?{duration:.12}:{type:'spring',stiffness:310,damping:27}} className="absolute bottom-0 left-0 top-0 w-7 bg-[#fb7185]"/><AnimatePresence mode="wait"><motion.div key={label} initial={{opacity:0,x:reduced?0:10}} animate={{opacity:1,x:0}} exit={{opacity:0,x:reduced?0:-10}} transition={{duration:reduced?.12:.18}} className="relative pl-5"><p className="text-xs font-bold uppercase tracking-[.14em] text-[#4a4a4f]">sheet 0{reviewed?2:1}</p><h2 className="mt-1 text-xl font-black text-[#111]">{label}</h2><p className="mt-2 text-sm text-[#4a4a4f]">{reviewed?'Notes were reconciled and approved.':'Notes are waiting for an editorial pass.'}</p></motion.div></AnimatePresence></div><motion.button type="button" aria-pressed={reviewed} onClick={()=>setReviewed(!reviewed)} whileHover={reduced?undefined:{y:-2}} whileTap={reduced?undefined:{y:1}} className="mt-4 min-h-11 w-full rounded-xl bg-[#111] text-sm font-bold text-white outline-offset-3 focus-visible:outline focus-visible:outline-[3px] focus-visible:outline-[#111]">Show {reviewed?'draft':'reviewed'} sheet</motion.button><p aria-live="polite" className="mt-3 text-xs text-[#4a4a4f]">Active sheet: {label}.</p></section>}
